oxy_webhelp_navlinks = {"manage_protection_olvm_vms-d26997e24059":{"topics":[{"title":"Adding an OLVM virtual machine","shortdesc":"<p class=\"shortdesc\">Add an Oracle Linux Virtualization Manager virtual machine to enable automated         snapshot creation and data protection through SLA Domains.<\/p>","href":"OLVM\/adding_olvm_vm.html","attributes":{"data-id":"adding_olvm_vm"},"menu":{"hasChildren":false},"tocID":"adding_olvm_vm-d26997e24072","topics":[]},{"title":"Assigning an SLA Domain to OLVM","shortdesc":"<p class=\"shortdesc\">Assign an SLA Domain to Oracle Linux Virtualization Manager virtual machines to         automate data protection, retention, and archival.<\/p>","href":"OLVM\/assigning_sla_domains_olvm.html","attributes":{"data-id":"assigning_sla_domains_olvm"},"menu":{"hasChildren":false},"tocID":"assigning_sla_domains_olvm-d26997e24083","topics":[]},{"title":"Taking an on-demand snapshot for OLVM","shortdesc":"<p class=\"shortdesc\">You can initiate an on-demand snapshot of an Oracle Linux Virtualization Manager         virtual machine to capture its state at a specific point in time. <\/p>","href":"OLVM\/taking_on-demand_snapshot_olvm.html","attributes":{"data-id":"taking_on-demand_snapshot_olvm"},"menu":{"hasChildren":false},"tocID":"taking_on-demand_snapshot_olvm-d26997e24094","topics":[]},{"title":"Placing an OLVM snapshot on legal hold","shortdesc":"<p class=\"shortdesc\">Place a legal hold on an Oracle Linux Virtualization Manager virtual machine snapshot         to retain it indefinitely.<\/p>","href":"OLVM\/placing_olvm_snapshot_legal_hold.html","attributes":{"data-id":"placing_olvm_snapshot_legal_hold"},"menu":{"hasChildren":false},"tocID":"placing_olvm_snapshot_legal_hold-d26997e24105","topics":[]}]}};